THOUGHT: The build failed because I added sanitizeShuffleMask as a method of ShuffleInstructionBuilder, but the inserted calls are inside BaseShuffleAnalysis::createShuffle, where that helper isn’t visible. I will add sanitizeShuffleMask as a static method of BaseShuffleAnalysis (near combineMasks), so the unqualified calls inside BaseShuffleAnalysis methods resolve correctly.

```bash
python3 - << 'PY'
from pathlib import Path
p = Path('llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp')
s = p.read_text()

anchor = 'static void combineMasks(unsigned LocalVF, SmallVectorImpl<int> &Mask,'
pos = s.find(anchor)
if pos == -1:
    print("combineMasks anchor not found")
    raise SystemExit(1)

# Find the end of combineMasks function by locating the next line after 'Mask.swap(NewMask);' followed by '}'.
comb_end = s.find('Mask.swap(NewMask);', pos)
if comb_end == -1:
    print("combineMasks body end not found")
    raise SystemExit(1)
# move to end of line containing Mask.swap(NewMask);
comb_end = s.find('\n', comb_end)
# next, find the first closing brace after that
brace_end = s.find('}', comb_end)
if brace_end == -1:
    print("combineMasks closing brace not found")
    raise SystemExit(1)

insert_loc = brace_end + 1
helper_code = """
	  /// Ensure shuffle masks do not contain out-of-range indices for the target
	  /// shuffle. Replace invalid indices with poison to keep shuffles valid.
	  /// For single-operand shuffles, valid indices are [0, VF).
	  /// For two-operand shuffles, valid indices are [0, 2*VF).
	  static void sanitizeShuffleMask(MutableArrayRef<int> M, unsigned VF,
	                                  bool HasSecondOp) {
	    const int Max = HasSecondOp ? static_cast<int>(2 * VF) : static_cast<int>(VF);
	    for (int &I : M) {
	      if (I == PoisonMaskElem)
	        continue;
	      if (I < 0 || I >= Max)
	        I = PoisonMaskElem;
	    }
	  }
"""
if 'sanitizeShuffleMask(MutableArrayRef<int> M' not in s:
    s = s[:insert_loc] + helper_code + s[insert_loc:]
    p.write_text(s)
    print("Inserted BaseShuffleAnalysis::sanitizeShuffleMask")
else:
    print("sanitizeShuffleMask already present; no changes")
PY
```

